import { useState } from "react";

import { AnimatePresence, motion } from "framer-motion";
import { Button } from "@nextui-org/react";

import { TbChevronRightPipe } from "react-icons/tb";

export default function AccordionPrices({
  children = null,
  title = null,
  className = "",
  classNames = {},
}) {
  const [open, setOpen] = useState(false);

  return (
    <div
      className={`flex flex-col items-end gap-2 sm:flex-row-reverse sm:items-start${
        className ? " " + className : ""
      }`}
      data-slot="wrapper"
    >
      {children && (
        <Button
          isIconOnly
          color="secondary"
          radius="sm"
          className="mx-2"
          onPress={() => setOpen(!open)}
        >
          <TbChevronRightPipe
            className={`transition-all h-4/5 w-fit -rotate-90${
              open ? " rotate-90" : ""
            }`}
          />
        </Button>
      )}

      <div
        className={`max-sm:w-full border-3 font-bold rounded-xl bg-content1 py-2 px-4${
          classNames?.container ? " " + classNames.container : ""
        }`}
      >
        {title || <div></div>}

        <AnimatePresence initial={false}>
          {open && (
            <motion.div
              initial={{ height: 0, opacity: 0 }}
              animate={{ height: "auto", opacity: 1 }}
              exit={{ height: 0, opacity: 0 }}
              transition={{ duration: 0.3 }}
              className={`overflow-hidden${
                classNames?.content ? " " + classNames.content : ""
              }`}
              data-slot="container"
            >
              {children}
            </motion.div>
          )}
        </AnimatePresence>
      </div>
    </div>
  );
}
