import { motion } from "framer-motion";
import { useOutletContext } from "react-router";

import { title1 } from "../../libs/tvs";
import { toPriceFormat } from "../../libs/functions";

import { Divider } from "@nextui-org/react";

import ImageCustom from "../../components/ImageCustom";
import AccordionPrices from "./AccordionPrices";

import ButtonAddCart from "../../components/ButtonAddCart";

export default function TableOthers({ items = [], catId = "" }) {
  const context = useOutletContext();

  return (
    <motion.article
      className="xs:place-self-center space-y-6"
      variants={{
        hidden: {},
        visible: {
          transition: {
            delayChildren: 0.1,
            staggerChildren: 0.2,
          },
        },
      }}
      initial="hidden"
      whileInView="visible"
    >
      {items?.map((item, i) => {
        let price = item?.price;
        if (item?.prices) price = item?.prices[0];
        const discount_ =
          item.cartData.discounts?.[item?.discountToUse] || false;
        const price_measure = item?.price_measure || "u";
        const noStock = item?.noStock;

        const cartCat = context?.cart?.value?.[catId];
        const inCart = cartCat && item.cartData.id in cartCat;

        return (
          <motion.div
            key={i}
            className="flex flex-col items-center sm:grid sm:grid-cols-5 sm:items-start gap-6 px-2 py-4 xs:min-w-[250px] max-w-[900px]"
            variants={{
              hidden: { opacity: 0, y: -200 },
              visible: { opacity: 1, y: 0 },
            }}
          >
            <div className="sm:self-center sm:col-span-2">
              <ImageCustom
                src={item?.img}
                alt={item?.label}
                width={300}
                className="sm:max-h-[250px] sm:object-contain"
                style={{
                  filter: "drop-shadow(2px 4px 6px black)",
                }}
              />
            </div>

            <div className="w-full flex flex-col justify-between py-2 sm:col-span-3">
              <div className="text-start">
                <h1
                  className={`${title1({
                    color: "custom2",
                    darkColor: "custom1",
                  })} capitalize pe-4 max-xs:break-all`}
                >
                  {item?.label}
                </h1>

                <Divider className="mb-2" />

                {item?.caracteristicas && (
                  <div className="flex flex-wrap gap-4">
                    {item?.caracteristicas.map((caract) => (
                      <b key={caract} className="capitalize break-words italic">
                        {caract}
                      </b>
                    ))}
                  </div>
                )}

                {item?.info &&
                  Object.entries(item?.info).map(([key, value]) => (
                    <p key={key} className="break-words">
                      <b className="capitalize">{key}: </b>
                      {value}
                    </p>
                  ))}

                {item?.description ? item?.description + "." : ""}
              </div>
            </div>

            <div className="w-full sm:col-span-5">
              <AccordionPrices
                className="w-full sm:w-fit xs:place-self-end"
                classNames={{
                  content: "mt-4 space-y-4",
                  container:
                    "shadow-md" +
                    (noStock ? " bg-divider" : "") +
                    (item?.id in (context?.cart?.value?.[catId] || {})
                      ? " border-success"
                      : noStock
                      ? " border-default"
                      : " border-custom1-2"),
                }}
                title={
                  <div className="text-2xl flex items-center justify-between gap-2 max-sm:break-all max-sm:flex-wrap hover:text-custom1 transition-colors">
                    <div>
                      {discount_ && (
                        <>
                          <div className="text-danger text-lg">
                            -
                            {Intl.NumberFormat("es-AR", {
                              style: "percent",
                              minimumFractionDigits: 0,
                              maximumFractionDigits: 0,
                            }).format(discount_)}
                          </div>
                          <div>
                            {toPriceFormat(
                              price * (discount_ ? 1 - discount_ : 1)
                            )}
                            {item?.price_measure && "/" + item?.price_measure}
                          </div>
                        </>
                      )}

                      <div
                        className={`${
                          discount_
                            ? "line-through text-neutral-500 text-lg"
                            : ""
                        }`}
                      >
                        {toPriceFormat(price)}
                        {item?.price_measure && "/" + item?.price_measure}
                      </div>
                    </div>

                    <ButtonAddCart
                      catId={catId}
                      cartData={item.cartData}
                      inCart={inCart && cartCat[item.cartData.id]?.qtt === 1}
                      handleAdd={context?.cart?.add}
                    />
                  </div>
                }
              >
                {item?.prices &&
                  item.prices.map((p, i) => {
                    if (i > 0) {
                      const qtt_ = item.qtts[i];
                      const cartData_ = { ...item.cartData, qtt: qtt_ };
                      return (
                        <div
                          key={i}
                          className="text-2xl flex justify-between gap-2 max-sm:break-all max-sm:flex-wrap hover:text-custom1 transition-colors "
                        >
                          <span>
                            {toPriceFormat(p)}/{price_measure}
                          </span>

                          <span>x{item?.qtts[i] + price_measure}</span>

                          <ButtonAddCart
                            catId={catId}
                            cartData={cartData_}
                            inCart={
                              inCart && cartCat[cartData_.id]?.qtt === qtt_
                            }
                            handleAdd={context?.cart?.add}
                          />
                        </div>
                      );
                    }
                    return null;
                  })}
              </AccordionPrices>
            </div>

            {i !== items?.length - 1 && (
              <Divider className="sm:hidden w-2/3 self-center" />
            )}
          </motion.div>
        );
      })}
    </motion.article>
  );
}
